          let entmEdids = String(item.ENTM_EDID||'').split(';').map(s=>s.trim()).filter(Boolean);
          const ExactPairs={'SCRAPBOX':'F1_ENTM_CAMP_ScrapBox_Standard','AMMO STORAGE BOX':'F1_ENTM_CAMP_AmmoStorageBox_Standard','AID BOX':'F1_ENTM_CAMP_AidBox_Standard'};
          const normStr=txt=>String(txt||'').toUpperCase().replace(/[^A-Z0-9]/g,'');
          function findRemove(pred){const idx=entmEdids.findIndex(pred);return idx>=0?entmEdids.splice(idx,1)[0]:'';}
          const reservedEdidMap={};
          entmFulls.forEach(full=>{const key=full.trim().toUpperCase();if(ExactPairs[key]){const exp=ExactPairs[key];const m=findRemove(e=>e.toUpperCase()===exp.toUpperCase())||findRemove(e=>e.toUpperCase().includes(exp.toUpperCase()))||findRemove(e=>exp.toUpperCase().includes(e.toUpperCase()));if(m)reservedEdidMap[full]=m;}});
          function pickBestEdid(fullName){if(!entmEdids.length)return'';const fn=normStr(fullName);let idx=entmEdids.findIndex(e=>normStr(e)===fn);if(idx>=0)return entmEdids.splice(idx,1)[0];idx=entmEdids.findIndex(e=>fullName.includes(e)||e.includes(fullName));if(idx>=0)return entmEdids.splice(idx,1)[0];const ft=fullName.toUpperCase().split(/[^A-Z0-9]+/).filter(Boolean);let bi=-1,bs=0;entmEdids.forEach((e,i)=>{const et=e.toUpperCase().split(/[^A-Z0-9]+/).filter(Boolean);const s=ft.reduce((s,t)=>s+(et.includes(t)?1:0),0);if(s>bs){bs=s;bi=i;}});if(bi>=0&&bs>0)return entmEdids.splice(bi,1)[0];return entmEdids.length?entmEdids.splice(0,1)[0]:'';}

